#!/bin/bash

set -Efeuxo pipefail

APP="Unlag Neo"

DISPLAY_NAME="Unlag Neo"

if [ -e "${APP}.app" ]; then

echo "Error: ${APP}.app exists already"

exit 1

fi

mkdir -vp "${APP}.app/Contents/MacOS" "${APP}.app/Contents/Resources"

PATH="$PATH:/usr/libexec"

swiftc - -o "${APP}.app/Contents/MacOS/${APP}" <<'SWIFT'

import Foundation

